const envelope = items[0]?.json ?? {};
const payload = envelope?.body ?? {};
const formData = payload?.data ?? {};
const fields = Array.isArray(formData?.fields) ? formData.fields : [];

const FIELD_KEYS = Object.freeze({
  TRAVEL_LIFESTYLE: 'question_y6lBLd',
  AGE_GROUP: 'question_XDepXz',
  TRAINING_ENVIRONMENT: 'question_8KdXOr',
  TRAINING_IMPLEMENTATION: 'question_0xEKXA',
  FOCUS: 'question_zqKklg',
  ACTIVITY_LEVEL: 'question_lyNxQX',
  ACTIVITY_TYPE: 'question_R0zApQ',
  DAILY_SCHEDULE: 'question_oyAqWN',
  SLEEP_AMOUNT: 'question_GzrZWO',
  GENDER: 'question_V0ZKg6',
  CYCLE_ADJUST: 'question_DNr5Nb',
  CYCLE_PHASE: 'question_lyoLy5',
  MINDFUL_AREAS: 'question_P6A7Kx',
  NAME: 'question_R0XR0l',
  EMAIL: 'question_jyBjN1',
});

function normalizeText(value) {
  if (value == null) { return null; }
  return String(value)
    .replace(/\u00A0/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function buildFieldMap(fieldList) {
  const result = {};
  for (const field of fieldList) {
    if (field?.key) { result[field.key] = field; }
  }
  return result;
}

function extractMultipleChoice(field) {
  if (!field) { return null; }
  const selectedIds = Array.isArray(field.value) ? field.value : field.value != null ? [field.value] : [];
  if (selectedIds.length === 0) { return null; }
  const options = Array.isArray(field.options) ? field.options : [];
  const optionTextById = {};
  for (const option of options) {
    if (option?.id) { optionTextById[option.id] = normalizeText(option.text); }
  }
  const selectedTexts = selectedIds.map(id => optionTextById[id] ?? null).filter(Boolean);
  if (selectedTexts.length === 0) { return null; }
  return selectedTexts.length === 1 ? selectedTexts[0] : selectedTexts;
}

function extractScalar(field) {
  if (!field || field.value == null) { return null; }
  return typeof field.value === 'string' ? normalizeText(field.value) : field.value;
}

function extractValue(field) {
  if (!field) { return null; }
  switch (field.type) {
    case 'MULTIPLE_CHOICE': return extractMultipleChoice(field);
    case 'INPUT_TEXT':
    case 'INPUT_EMAIL': return extractScalar(field);
    default: return extractScalar(field);
  }
}

const fieldMap = buildFieldMap(fields);

return [{
  json: {
    tally: {
      eventId: payload.eventId ?? null,
      eventType: payload.eventType ?? null,
      createdAt: payload.createdAt ?? null,
      responseId: formData.responseId ?? null,
      submissionId: formData.submissionId ?? null,
      respondentId: formData.respondentId ?? null,
      formId: formData.formId ?? null,
      formName: normalizeText(formData.formName),
      createdAtFormResponse: formData.createdAt ?? null,
    },
    lead: {
      name: extractValue(fieldMap[FIELD_KEYS.NAME]),
      email: extractValue(fieldMap[FIELD_KEYS.EMAIL]),
      travelLifestyle: extractValue(fieldMap[FIELD_KEYS.TRAVEL_LIFESTYLE]),
      ageGroup: extractValue(fieldMap[FIELD_KEYS.AGE_GROUP]),
      trainingEnvironment: extractValue(fieldMap[FIELD_KEYS.TRAINING_ENVIRONMENT]),
      trainingImplementation: extractValue(fieldMap[FIELD_KEYS.TRAINING_IMPLEMENTATION]),
      focus: extractValue(fieldMap[FIELD_KEYS.FOCUS]),
      activityLevel: extractValue(fieldMap[FIELD_KEYS.ACTIVITY_LEVEL]),
      activityType: extractValue(fieldMap[FIELD_KEYS.ACTIVITY_TYPE]),
      dailySchedule: extractValue(fieldMap[FIELD_KEYS.DAILY_SCHEDULE]),
      sleepAmount: extractValue(fieldMap[FIELD_KEYS.SLEEP_AMOUNT]),
      gender: extractValue(fieldMap[FIELD_KEYS.GENDER]),
      cycleAdjust: extractValue(fieldMap[FIELD_KEYS.CYCLE_ADJUST]),
      cyclePhase: extractValue(fieldMap[FIELD_KEYS.CYCLE_PHASE]),
      mindfulAreas: extractValue(fieldMap[FIELD_KEYS.MINDFUL_AREAS]),
    }
  }
}];

const payload = items[0].json;
const lead    = payload.lead || {};

const GOAL_MAP = {
  'Energize & Refocus':      'energy',
  'De-Stress & Reset':       'destress',
  'Posture & Mobility Flow': 'posture',
  'Stay Fit & Active':       'active',
  'Core & Balance':          'core',
  'Energize / refocus (mornings, post-flight fatigue)': 'energy',
  'De-Stress / reset (calm, unwind after long days)':   'destress',
  'Posture / mobility (counter long hours of sitting)': 'posture',
  'Stay fit / active (keep strength and movement)':     'active',
  'Core / balance (control and coordination)':          'core',
};
const SPACE_MAP = {
  'Indoor':             'indoor',
  'Outdoors':           'outdoors',
  'Mixed environment':  'mixed',
  'Mixed':              'mixed',
  'Indoors (hotel room, Airbnb, apartment)': 'indoor',
  'Outdoors (park, beach, rooftop, terrace)': 'outdoors',
  'Mixed environments (varies day to day)': 'mixed',
};
const EQUIP_MAP = {
  'Bodyweight only':             'none',
  'Bodyweight + everyday items': 'everyday_items',
  'Bodyweight + Everyday Items': 'everyday_items',
  'Bodyweight + items (backpack, bottles of water)': 'everyday_items',
};
const LEVEL_MAP = {
  'Beginner':     'beginner',
  'Intermediate': 'intermediate',
  'Advanced':     'advanced',
  'Intermediate (active, but inconsistent)': 'intermediate',
  'Beginner (just starting out)':            'beginner',
  'Beginner (new, returning to exercise)':   'beginner',
  'Advanced (very consistent)':              'advanced',
  'Advanced (comfortable with higher intensity)': 'advanced',
};
const CONTRA_MAP = {
  'Low Back':               'low_back_pain',
  'Low back sensitivity':   'low_back_pain',
  'Knees':                  'knee_pain',
  'Knee sensitivity':       'knee_pain',
  'Shoulders':              'shoulders_pain',
  'Shoulders sensitivity':  'shoulders_pain',
  'High Stress':            'stress',
  'High Stress / fatigue':  'stress',
  'High stress / feeling fatigued': 'stress',
  'None, feeling good':      null,
  'None, I\'m feeling good': null,
  'None':                    null,
};
const SLEEP_MAP = {
  'Less than 5 hours': 'very_low',
  'Under 5 hours':     'very_low',
  '5 hours':           'very_low',
  '6-7 hours':         'normal',
  '6\u20137 hours':    'normal',
  'More than 8 hours': 'high',
  '8+ hours':          'high',
  '8 or more':         'high',
};
const MOVEMENT_MAP = {
  'Cardio':                                        'cardio',
  'Resistance':                                    'resistance',
  'Resistance / strength (weights, bodyweights)': 'resistance',
  'Yoga / Pilates':                                'mobility',
  'Yoga/Pilates':                                  'mobility',
  'Yoga / pilates / dance':                        'mobility',
  'Mixed':                                         'mix',
  'Balanced routine':                              'mix',
  'Balanced mix':                                  'mix',
  'Cardio-based':                                  'cardio',
  'Cardio-based (running, cycling, swimming)':     'cardio',
  'Resistance / strength':                         'resistance',
};
const CYCLE_MAP = {
  'Menstrual phase':  'menstrual',
  'Follicular phase': 'follicular',
  'Ovulatory phase':  'ovulatory',
  'Luteal phase':     'luteal',
  'Not applicable':   'none',
  'Not sure / Prefer not to say / Skip': 'none',
};

const rawAreas = Array.isArray(lead.mindfulAreas)
  ? lead.mindfulAreas
  : lead.mindfulAreas
    ? [lead.mindfulAreas]
    : [];

const user_profile = {
  primary_goal:      GOAL_MAP[lead.focus]                   || lead.focus                                      || null,
  space:             SPACE_MAP[lead.trainingEnvironment]    || (lead.trainingEnvironment   || '').toLowerCase() || null,
  equipment:         EQUIP_MAP[lead.trainingImplementation] || (lead.trainingImplementation || '').toLowerCase() || null,
  level:             LEVEL_MAP[lead.activityLevel]          || (lead.activityLevel         || '').toLowerCase() || 'beginner',
  movement_type:     MOVEMENT_MAP[lead.activityType]        || (lead.activityType          || '').toLowerCase() || null,
  sleep_bucket:      SLEEP_MAP[lead.sleepAmount]            || 'normal',
  sex:               (lead.gender || '').toLowerCase()      || 'undisclosed',
  cycle_phase:       CYCLE_MAP[lead.cyclePhase]             || 'none',
  contraindications: rawAreas.map(a => CONTRA_MAP[a] ?? null).filter(Boolean),
  lifestyle:         (lead.travelLifestyle || '').toLowerCase().replace(/\s+/g, '_') || null,
  age_group:         (lead.ageGroup        || '').toLowerCase().replace(/\s+/g, '_') || null,
};

return [{
  json: {
    name:          lead.name  || 'Unknown',
    email:         lead.email || 'unknown@example.com',
    status:        'new',
    tally_payload: JSON.stringify(payload),
    user_profile:  JSON.stringify(user_profile),
  }
}];

const key = String($env.PADDLE_API_KEY || '').trim();
const rawUrl = String($env.PADDLE_API_URL || '').trim();
const priceId = String($env.PADDLE_PRICE_ID || '').trim();

if (!key) {
  throw new Error('PADDLE_API_KEY is empty. Set server-side Paddle API key (pdl_sdbx_* or pdl_live_*).');
}
if (!rawUrl) {
  throw new Error('PADDLE_API_URL is empty. Use https://sandbox-api.paddle.com or https://api.paddle.com');
}
if (!priceId) {
  throw new Error('PADDLE_PRICE_ID is empty. Set pri_* from Paddle Catalog.');
}
if (!priceId.startsWith('pri_')) {
  throw new Error(`PADDLE_PRICE_ID must start with pri_. Got: ${priceId}`);
}

if (key.startsWith('test_') || key.startsWith('live_')) {
  throw new Error('Wrong Paddle token type in PADDLE_API_KEY. Use API key (pdl_sdbx_* / pdl_live_*), not client-side token (test_*/live_*).');
}
if (!(key.startsWith('pdl_sdbx_') || key.startsWith('pdl_live_'))) {
  throw new Error('Unexpected PADDLE_API_KEY format. Expected pdl_sdbx_* or pdl_live_*.');
}

const apiUrl = rawUrl.replace(/\/+$/, '');
const isSandboxUrl = apiUrl.includes('sandbox-api.paddle.com');
const isProdUrl = apiUrl.includes('api.paddle.com') && !isSandboxUrl;

if (!(isSandboxUrl || isProdUrl)) {
  throw new Error(`Unsupported PADDLE_API_URL: ${apiUrl}. Use https://sandbox-api.paddle.com or https://api.paddle.com`);
}
if (key.startsWith('pdl_sdbx_') && !isSandboxUrl) {
  throw new Error('Environment mismatch: sandbox API key requires PADDLE_API_URL=https://sandbox-api.paddle.com');
}
if (key.startsWith('pdl_live_') && !isProdUrl) {
  throw new Error('Environment mismatch: live API key requires PADDLE_API_URL=https://api.paddle.com');
}

return [{
  json: {
    paddle_api_key: key,
    paddle_api_url: apiUrl,
    paddle_price_id: priceId
  }
}];

