const txn = $('Create Paddle Transaction').first().json || {};
const txnData = txn.data || {};
const txnId = txnData.id || '';
const baseUrl = ($env.PADDLE_API_URL || '').includes('sandbox') ? 'https://sandbox-buy.paddle.com' : 'https://buy.paddle.com';
const checkoutUrl = txnData.checkout?.url || (txnId ? `${baseUrl}/checkout/${txnId}` : '');
const rec = $('Save to PostgreSQL').first().json || {};

return [{
  json: {
    redirectUrl: checkoutUrl,
    status: 'pending_payment',
    lead_id: rec.id || '',
    email: rec.email || '',
    checkout_url: checkoutUrl
  }
}];
